import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);

  const [tab, setTab] = useState('users');
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');

  const [modal, setModal] = useState({
    show: false,
    type: '',
    id: null,
    action: null
  });

  // ================= FETCH =================
  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data || []));
    API.get('/admin/posts').then(res => setPosts(res.data || []));
    API.get('/admin/comments').then(res => setComments(res.data || []));
    API.get('/admin/messages').then(res => setMessages(res.data || []));
  }, []);

  // ================= MODAL =================
  const openModal = (type, id, action) => {
    setModal({ show: true, type, id, action });
  };

  const closeModal = () => {
    setModal({ show: false, type: '', id: null, action: null });
  };

  const confirmAction = async () => {
    const { type, id, action } = modal;

    try {
      if (type === 'user') {
        const { data } = await API.put(`/admin/users/${id}/status`);
        setUsers(prev => prev.map(u => (u._id === id ? data.user : u)));
      }

      if (type === 'post') {
        await API.delete(`/posts/${id}`);
        setPosts(prev => prev.filter(p => p._id !== id));
      }

      if (type === 'comment') {
        await API.delete(`/comments/${id}`);
        setComments(prev => prev.filter(c => c._id !== id));
      }

      if (type === 'message' && action === 'delete') {
        await API.delete(`/admin/messages/${id}`);
        setMessages(prev => prev.filter(m => m._id !== id));
      }

      if (type === 'message' && action === 'read') {
        await API.put(`/admin/messages/${id}/read`);
        setMessages(prev =>
          prev.map(m =>
            m._id === id ? { ...m, status: 'read', read: true } : m
          )
        );
      }

      closeModal();
    } catch {
      alert("Action failed.");
    }
  };

  // ================= HELPERS =================
  const getMessageStatus = (m) =>
    (m.status === 'read' || m.read || m.isRead) ? 'READ' : 'NEW';

  const isMessageRead = (m) =>
    (m.status === 'read' || m.read || m.isRead);

  // ================= FILTER =================
  const filteredData = () => {
    const keyword = search.toLowerCase();

    let dataMap = { users, posts, comments, messages };
    let data = dataMap[tab];

    data = data.filter(item =>
      JSON.stringify(item).toLowerCase().includes(keyword)
    );

    if (tab === 'users') {
      if (filter === 'active') data = data.filter(u => u.status === 'active');
      if (filter === 'inactive') data = data.filter(u => u.status !== 'active');
    }

    if (tab === 'posts') {
      if (filter === 'with-author') data = data.filter(p => p.author?.name);
      if (filter === 'no-author') data = data.filter(p => !p.author?.name);
    }

    if (tab === 'comments') {
      if (filter === 'with-text') data = data.filter(c => c.body);
      if (filter === 'empty') data = data.filter(c => !c.body);
    }

    if (tab === 'messages') {
      if (filter === 'read') data = data.filter(m => getMessageStatus(m) === 'READ');
      if (filter === 'unread') data = data.filter(m => getMessageStatus(m) === 'NEW');
    }

    return data;
  };

  // ================= COLORS =================
  const colors = {
    pinkBg: '#fdecef',
    pinkCard: '#fbd5e0',
    green: '#0c4b34',
    greenLight: '#1f7a5c',
    white: '#ffffff',
    border: '#e8a0b5'
  };

  // ================= STYLES =================
  const styles = {
    page: {
      background: colors.pinkBg,
      minHeight: '100vh',
      padding: '40px'
    },
    container: {
      maxWidth: '1150px',
      margin: 'auto',
      background: colors.pinkCard,
      padding: '30px',
      borderRadius: '25px',
      boxShadow: '0 10px 25px rgba(0,0,0,0.08)'
    },
    header: {
      textAlign: 'center',
      fontSize: '30px',
      fontWeight: '800',
      color: colors.green,
      marginBottom: '20px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '10px',
      marginBottom: '15px'
    },
    tab: {
      padding: '10px 18px',
      borderRadius: '20px',
      border: `2px solid ${colors.green}`,
      background: colors.white,
      cursor: 'pointer',
      fontWeight: '600'
    },
    activeTab: {
      background: colors.green,
      color: colors.white
    },
    filterBar: {
      display: 'flex',
      gap: '10px',
      marginBottom: '15px'
    },
    search: {
      flex: 1,
      padding: '10px',
      borderRadius: '10px',
      border: `1px solid ${colors.border}`
    },
    select: {
      padding: '10px',
      borderRadius: '10px',
      border: `1px solid ${colors.border}`
    },
    tableWrapper: {
      maxHeight: '450px',
      overflowY: 'auto',
      borderRadius: '15px',
      border: `2px solid ${colors.green}`
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse'
    },
    th: {
      position: 'sticky',
      top: 0,
      background: colors.green,
      color: colors.white,
      padding: '12px',
      textAlign: 'left'
    },
    td: {
      padding: '12px',
      borderBottom: `1px solid ${colors.border}`,
      color: colors.green,
      fontWeight: '600'
    },
    btn: {
      padding: '6px 12px',
      borderRadius: '10px',
      border: 'none',
      cursor: 'pointer',
      marginRight: '5px',
      fontWeight: '600'
    },
    modalOverlay: {
      position: 'fixed',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      background: 'rgba(0,0,0,0.5)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center'
    },
    modalBox: {
      background: '#fff',
      padding: '25px',
      borderRadius: '15px',
      textAlign: 'center',
      width: '300px'
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.header}>Admin Dashboard</div>

        {/* TABS */}
        <div style={styles.tabs}>
          {['users', 'posts', 'comments', 'messages'].map(t => (
            <button
              key={t}
              onClick={() => {
                setTab(t);
                setSearch('');
                setFilter('all');
              }}
              style={{
                ...styles.tab,
                ...(tab === t ? styles.activeTab : {})
              }}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        {/* FILTER */}
        <div style={styles.filterBar}>
          <input
            style={styles.search}
            placeholder={`Search ${tab}`}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <select
            style={styles.select}
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          >
            <option value="all">All</option>
            <option value="active">Active</option>
            <option value="inactive">Inactive</option>
          </select>
        </div>

        {/* TABLE */}
        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              <tr>
                {tab === 'users' && (
                  <>
                    <th style={styles.th}>Name</th>
                    <th style={styles.th}>Email</th>
                    <th style={styles.th}>Status</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {tab === 'posts' && (
                  <>
                    <th style={styles.th}>Title</th>
                    <th style={styles.th}>Author</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {tab === 'comments' && (
                  <>
                    <th style={styles.th}>Author</th>
                    <th style={styles.th}>Comment</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {/* ✅ FIXED MESSAGES HEADER */}
                {tab === 'messages' && (
                  <>
                    <th style={styles.th}>Name</th>
                    <th style={styles.th}>Email</th>
                    <th style={styles.th}>Message</th>
                    <th style={styles.th}>Status</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}
              </tr>
            </thead>

            <tbody>
              {/* USERS */}
              {tab === 'users' && filteredData().map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: colors.green, color: '#fff' }}
                      onClick={() => openModal('user', u._id)}
                    >
                      TOGGLE
                    </button>
                  </td>
                </tr>
              ))}

              {/* POSTS */}
              {tab === 'posts' && filteredData().map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                      onClick={() => openModal('post', p._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {/* COMMENTS */}
              {tab === 'comments' && filteredData().map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                      onClick={() => openModal('comment', c._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {/* ✅ FIXED MESSAGES BODY */}
              {tab === 'messages' && filteredData().map(m => (
                <tr key={m._id}>
                  <td style={styles.td}>{m.name}</td>
                  <td style={styles.td}>{m.email}</td>
                  <td style={styles.td}>{m.body || m.message}</td>
                  <td style={styles.td}>{getMessageStatus(m)}</td>
                  <td style={styles.td}>
                    {!isMessageRead(m) && (
                      <button
                        style={{ ...styles.btn, background: colors.green, color: '#fff' }}
                        onClick={() => openModal('message', m._id, 'read')}
                      >
                        Mark Read
                      </button>
                    )}

                    <button
                      style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                      onClick={() => openModal('message', m._id, 'delete')}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* MODAL */}
        {modal.show && (
          <div style={styles.modalOverlay}>
            <div style={styles.modalBox}>
              <h3>Confirm Action</h3>
              <p>Are you sure?</p>

              <button
                style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                onClick={confirmAction}
              >
                Yes
              </button>

              <button
                style={{ ...styles.btn, background: '#ccc' }}
                onClick={closeModal}
              >
                Cancel
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPage;
